-- Session 4 — Enable pg_trgm and add trigram GIN indexes for canonical-library
-- autocomplete search.
--
-- The Session 4 estimate UI introduces an autocomplete dropdown that fuzzy-
-- searches the canonical library by name (stages, works, resources) and a
-- resource modal that browses subcategory siblings. The existing btree name
-- indexes only support prefix/equality lookups; trigram GIN indexes let
-- `similarity()` ranking and `ILIKE '%term%'` substring matching run against an
-- index instead of a sequential scan. For the curated wave-1 working set the
-- row counts are small (30 stages, 692 works, ~3.8K curated resources), so this
-- is primarily forward-looking — it keeps search fast if/when the full ~83K KSR
-- catalog becomes searchable.
--
-- pg_trgm is a standard, always-available Postgres contrib extension on both
-- Supabase Cloud (staging) and the self-host prod VPS. This migration adds no
-- data and no contract surface (no tables/functions/grants) — indexes only.
--
-- NOTE: plain CREATE INDEX (not CONCURRENTLY) is correct inside a migration —
-- migrations run in a transaction and CONCURRENTLY cannot. The brief lock on
-- system_resource_articles is acceptable for a one-time index build.

create extension if not exists pg_trgm;

-- Resource articles: search both the raw KSR `name` and the curated
-- `canonical_name` (the human-facing label the dropdown shows).
create index if not exists idx_system_resource_articles_name_trgm
  on public.system_resource_articles using gin (name gin_trgm_ops);

create index if not exists idx_system_resource_articles_canonical_name_trgm
  on public.system_resource_articles using gin (canonical_name gin_trgm_ops)
  where canonical_name is not null;

create index if not exists idx_system_stage_articles_name_trgm
  on public.system_stage_articles using gin (name gin_trgm_ops);

create index if not exists idx_system_work_articles_name_trgm
  on public.system_work_articles using gin (name gin_trgm_ops);
